// C0688 · Auth por sesión (login/logout)
import Fastify from "fastify";
import cookie from "@fastify/cookie";   // npm i @fastify/cookie
import session from "@fastify/session"; // npm i @fastify/session
const app = Fastify();

await app.register(cookie);
await app.register(session, {
  secret: process.env.SESSION_SECRET || "dev-secret-dev-secret-dev-secret-dev-secret",
  cookie: { secure: false }
});

