// C0692 · File upload multipart
import Fastify from "fastify";
import multipart from "@fastify/multipart"; // npm i @fastify/multipart
import fs from "node:fs";
import path from "node:path";
const app = Fastify();
await app.register(multipart);

app.post("/upload", async (req)=>{
  const file = await req.file();
  await fs.promises.mkdir("uploads", { recursive: true });
  const outPath = path.join("uploads", file.filename);
  await fs.promises.writeFile(outPath, await file.toBuffer());
  return { savedAs: outPath };
});

